SELECT rrd.resource_rel_detail_id, rrd.resource_id, rrd.rel_resource_id, rrd.create_by, rrd.create_time, rrd.update_by, rrd.update_time, rrd.com_acct_id, rrd.rel_type_name, rrd.rel_status, rrd.rel_resource_info, r1.resource_type, r2.resource_type AS rel_resource_type, r2.resource_biz_type AS rel_resource_biz_type FROM ss_resource_rel_detail rrd LEFT JOIN ss_resource r1 ON rrd.resource_id = r1.resource_id LEFT JOIN ss_resource r2 ON rrd.rel_resource_id = r2.resource_id WHERE rrd.resource_id != #{viewResourceId}
AND rrd.rel_resource_info::jsonb->>'viewResourceId' = CAST(#{viewResourceId} AS TEXT)
AND JSON_EXTRACT(rrd.rel_resource_info, '$.viewResourceId') = #{viewResourceId}
AND JSON_VALUE(rrd.rel_resource_info, '$.viewResourceId') = TO_CHAR(#{viewResourceId})
AND rrd.rel_resource_info::jsonb->>'viewResourceId' = CAST(#{viewResourceId} AS TEXT)
ORDER BY rrd.create_time DESC

select a.resource_id, a.resource_name, a.resource_biz_type, a.resource_type, a.resource_desc, a.resource_source_pk_id from ss_resource_rel_detail b left join ss_resource a on a.resource_id = b.rel_resource_id
and a.resource_status = 2 and a.parent_resource_id < 0
and b.resource_id = #{request.resourceId}
and a.resourceName like concat('%', concat(#{request.resourceName}, '%'))
and a.resource_biz_type in
#{item}
and a.resource_id in
#{item}
and b.resource_id in
#{item}
